(()=>{const t=document.getElementById("movies");[{id:26,title:"Побег из Шоушенка",imdb:9.3,year:1994},{id:25,title:"Крёстный отец",imdb:9.2,year:1972},{id:27,title:"Крёстный отец 2",imdb:9,year:1974},{id:1047,title:"Тёмный рыцарь",imdb:9,year:2008},{id:223,title:"Криминальное чтиво",imdb:8.9,year:1994}].forEach(e=>{t.innerHTML+=`\n    <tr \n      data-id="${e.id}" \n      data-title="${e.title}" \n      data-year="${e.year}" \n      data-imdb="${e.imdb}"\n    >\n      <td>${e.id}</td>\n      <td>${e.title}</td>\n      <td>(${e.year})</td>\n      <td>imdb: ${e.imdb.toFixed(2)}</td>\n    </tr>\n  `});const e=Array.from(document.querySelectorAll("#movies tr")),a=Array.from(document.getElementsByTagName("th"));let d=0;setInterval(()=>{switch(d){case 0:e.sort((t,e)=>Number(t.dataset.id)-Number(e.dataset.id)),a[0].textContent="id ↓";break;case 1:e.sort((t,e)=>Number(e.dataset.id)-Number(t.dataset.id)),a[0].textContent="id ↑";break;case 2:e.sort((t,e)=>t.dataset.title.localeCompare(e.dataset.title));break;case 3:e.sort((t,e)=>e.dataset.title.localeCompare(t.dataset.title));break;case 4:e.sort((t,e)=>Number(t.dataset.year)-Number(e.dataset.year));break;case 5:e.sort((t,e)=>Number(e.dataset.year)-Number(t.dataset.year));break;case 6:e.sort((t,e)=>Number(t.dataset.imdb)-Number(e.dataset.imdb));break;case 7:e.sort((t,e)=>Number(e.dataset.imdb)-Number(t.dataset.imdb))}t.innerHTML="",e.forEach(e=>t.appendChild(e)),d=(d+1)%8},2e3)})();